// Extract sender id and message text from Facebook Messenger webhook payload
const body = $json;
let senderId = '';
let messageText = '';
if (body.entry && body.entry[0] && body.entry[0].messaging && body.entry[0].messaging[0]) {
  const msg = body.entry[0].messaging[0];
  senderId = msg.sender && msg.sender.id;
  if (msg.message && msg.message.text) messageText = msg.message.text;
  else if (msg.message && msg.message.attachments && msg.message.attachments[0]) messageText = msg.message.attachments[0].payload && msg.message.attachments[0].payload.url || '';
}
return [{ json: { senderId, messageText } }];

// Build Facebook Send API body using OpenAI reply
const senderId = $json.senderId || $json["senderId"];
let aiReply = '';

if (items[0].json.choices && items[0].json.choices[0] && items[0].json.choices[0].message) {
  aiReply = items[0].json.choices[0].message.content;
} else if (items[0].json.text) {
  aiReply = items[0].json.text;
} else if (items[0].json.output && items[0].json.output[0] && items[0].json.output[0].text) {
  aiReply = items[0].json.output[0].text;
}

return [{ json: { recipient: { id: senderId }, message: { text: aiReply } } }];
